    '这个版本不再提醒': 'No avisarme de esta versión',

    // ---------- Nombres de carpetas de acceso rápido ----------
    '主目录': 'Inicio',
    '桌面': 'Escritorio',
    '文档': 'Documentos',
    '下载': 'Descargas',

    // ---------- Varios ----------
    '刚刚': 'ahora mismo',

    // ---------- Nombres de temas (las 18 paletas de themes-patch.js) ----------
    '新孟菲斯': 'Neo-Memphis',
    '现代博物': 'Museo Moderno',
    '酸性时尚': 'Acid Pop',
    '未来社区': 'Comuna del Futuro',
